import React, { useState, useRef, useEffect } from 'react';
import { Camera, FileSpreadsheet, Send, Save, Download, FileCheck, Trash2, X, Aperture, ImagePlus, RotateCcw } from 'lucide-react';
import { RawDataForm, INITIAL_FORM_DATA, AttachedImage } from '../types';
import JSZip from 'jszip';

const LabelCell = ({ children }: { children?: React.ReactNode }) => (
  <div className="bg-gray-100 p-2 text-center text-sm font-bold border border-gray-400 flex items-center justify-center break-keep">
    {children}
  </div>
);

const InputCell = ({ 
  value, 
  onChange, 
  type = "text",
  placeholder = "",
  textSize = "text-sm"
}: { 
  value: string; 
  onChange: (val: string) => void;
  type?: string;
  placeholder?: string;
  textSize?: string;
}) => {
  const [inputType, setInputType] = useState(type === 'date' ? 'text' : type);

  return (
  <div className="border border-gray-400 p-1 bg-yellow-50">
    <input
      type={inputType}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      onFocus={(e) => {
        if (type === 'date') setInputType('date');
      }}
      onBlur={(e) => {
        if (type === 'date') setInputType('text');
      }}
      placeholder={placeholder}
      className={`w-full h-full px-1 py-1 text-center focus:outline-none focus:bg-white ${textSize} font-bold bg-transparent tracking-tighter`}
    />
  </div>
  );
};

const FormView: React.FC = () => {
  const [siteData, setSiteData] = useState<{ [key: number]: RawDataForm }>({
    1: { ...INITIAL_FORM_DATA },
    2: { ...INITIAL_FORM_DATA },
    3: { ...INITIAL_FORM_DATA },
    4: { ...INITIAL_FORM_DATA },
  });

  const [activeSite, setActiveSite] = useState<number>(1);
  const [showCamera, setShowCamera] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    return () => {
        stopCamera();
    };
  }, []);

  const startCamera = async () => {
      try {
          const stream = await navigator.mediaDevices.getUserMedia({
              video: { facingMode: 'environment' }
          });
          if (videoRef.current) {
              videoRef.current.srcObject = stream;
          }
          setShowCamera(true);
      } catch (err) {
          console.error(err);
          alert("카메라 권한을 허용해주세요.");
      }
  };

  const stopCamera = () => {
      if (videoRef.current && videoRef.current.srcObject) {
          const stream = videoRef.current.srcObject as MediaStream;
          stream.getTracks().forEach(track => track.stop());
          videoRef.current.srcObject = null;
      }
      setShowCamera(false);
  };

  const capturePhoto = () => {
      if (videoRef.current && showCamera) {
          const video = videoRef.current;
          const canvas = document.createElement('canvas');
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
              const dataUrl = canvas.toDataURL('image/jpeg');

              const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
              const newImage: AttachedImage = {
                  name: `Photo_${timestamp}.jpg`,
                  dataUrl: dataUrl
              };

              setSiteData(prev => ({
                  ...prev,
                  [activeSite]: {
                      ...prev[activeSite],
                      attachedImages: [...prev[activeSite].attachedImages, newImage]
                  }
              }));

              stopCamera();
              alert("사진이 촬영되어 첨부되었습니다.");
          }
      }
  };

  const currentData = siteData[activeSite];

  const handleInputChange = (key: keyof RawDataForm, value: string) => {
    setSiteData(prev => ({
      ...prev,
      [activeSite]: {
        ...prev[activeSite],
        [key]: value
      }
    }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      const newImages: AttachedImage[] = [];
      let processedCount = 0;

      files.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          newImages.push({
            name: file.name,
            dataUrl: reader.result as string
          });
          processedCount++;

          if (processedCount === files.length) {
             setSiteData(prev => ({
                ...prev,
                [activeSite]: {
                  ...prev[activeSite],
                  attachedImages: [...prev[activeSite].attachedImages, ...newImages] 
                }
             }));
             alert(`[SITE ${activeSite}] 사진 ${files.length}장이 추가되었습니다.`);
          }
        };
        reader.readAsDataURL(file);
      });
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const clearImages = (e: React.MouseEvent) => {
      e.stopPropagation();
      if(window.confirm(`SITE ${activeSite}의 첨부된 사진을 모두 삭제하시겠습니까?`)) {
          setSiteData(prev => ({
              ...prev,
              [activeSite]: {
                  ...prev[activeSite],
                  attachedImages: []
              }
          }));
      }
  };

  const downloadBlob = (blob: Blob, filename: string) => {
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const downloadUri = (uri: string, filename: string) => {
      const link = document.createElement("a");
      link.href = uri;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  }

  const getSafeString = (str?: string) => str?.trim() || 'null';

  const getCsvFileName = (data: RawDataForm) => {
    return `${getSafeString(data.receptionNumber)}_${getSafeString(data.inspectEndDate)}_${getSafeString(data.model)}_${getSafeString(data.serialNumber)}.csv`;
  };

  const getImageZipFileName = (data: RawDataForm) => {
      return `${getSafeString(data.receptionNumber)}_${getSafeString(data.inspectEndDate)}_${getSafeString(data.serialNumber)}`;
  };

  const generateCsvContent = (data: RawDataForm) => {
    const { attachedImages, ...csvData } = data;
    const headers = Object.keys(csvData).join(',');
    const values = Object.values(csvData).map(v => typeof v === 'string' ? v.replace(/,/g, ' ') : v).join(',');
    return "\uFEFF" + headers + "\n" + values;
  };

  const generateCsvUri = (data: RawDataForm) => {
    const csvContent = generateCsvContent(data);
    return encodeURI("data:text/csv;charset=utf-8," + csvContent);
  };

  const dataURLtoBlob = (dataurl: string): Blob => {
      const arr = dataurl.split(',');
      const mimeMatch = arr[0].match(/:(.*?);/);
      const mime = mimeMatch ? mimeMatch[1] : 'image/png';
      const bstr = atob(arr[1]);
      let n = bstr.length;
      const u8arr = new Uint8Array(n);
      while(n--){
          u8arr[n] = bstr.charCodeAt(n);
      }
      return new Blob([u8arr], {type:mime});
  }

  const downloadImagesAsZip = async (data: RawDataForm) => {
     if (data.attachedImages.length === 0) return;

     const zipName = getImageZipFileName(data);
     const zip = new JSZip();
     const usedNames = new Set<string>();

     data.attachedImages.forEach((img) => {
         const blob = dataURLtoBlob(img.dataUrl);
         let fileName = img.name;

         if (usedNames.has(fileName)) {
             const nameParts = fileName.lastIndexOf('.');
             const name = nameParts !== -1 ? fileName.substring(0, nameParts) : fileName;
             const ext = nameParts !== -1 ? fileName.substring(nameParts) : '';
             let counter = 1;
             while (usedNames.has(`${name}(${counter})${ext}`)) {
                 counter++;
             }
             fileName = `${name}(${counter})${ext}`;
         }
         usedNames.add(fileName);
         zip.file(fileName, blob);
     });

     const content = await zip.generateAsync({ type: "blob" });
     downloadBlob(content, `${zipName}.zip`);
  };

  const handleExportExcel = async () => {
    const encodedUri = generateCsvUri(currentData);
    const fileName = getCsvFileName(currentData);
    downloadUri(encodedUri, fileName);

    if (currentData.attachedImages.length > 0) {
        await new Promise(resolve => setTimeout(resolve, 500)); 
        await downloadImagesAsZip(currentData);
    }
  };

  const handleGlobalExport = async () => {
    if (!window.confirm("SITE 1 ~ 4의 데이터를 저장합니다.\n\n- 모든 엑셀 파일은 하나의 ZIP으로 묶입니다.\n- 사진 파일은 사이트별로 별도의 ZIP 파일로 저장됩니다.\n(브라우저 팝업 허용이 필요할 수 있습니다)")) {
      return;
    }

    const csvZip = new JSZip();
    let hasCsv = false;
    const dateStr = new Date().toISOString().split('T')[0];

    for (let i = 1; i <= 4; i++) {
      const data = siteData[i];
      const csvContent = generateCsvContent(data);
      const csvName = getCsvFileName(data);
      csvZip.file(csvName, csvContent);
      hasCsv = true;

      if (data.attachedImages && data.attachedImages.length > 0) {
         await downloadImagesAsZip(data);
         await new Promise(resolve => setTimeout(resolve, 500));
      }
    }

    if (hasCsv) {
        const content = await csvZip.generateAsync({ type: "blob" });
        downloadBlob(content, `전체데이터_${dateStr}.zip`);
    }
  };

  const handleSave = () => {
      alert(`SITE ${activeSite} 데이터가 임시 저장되었습니다.`);
  };

  return (
    <div className="flex flex-col h-full font-sans bg-white text-slate-900 relative">

      {/* Camera Overlay Modal */}
      {showCamera && (
        <div className="fixed inset-0 z-50 bg-black flex flex-col">
            <div className="flex justify-between items-center p-4 text-white">
                <span className="font-bold">현장 사진 촬영 (SITE {activeSite})</span>
                <button onClick={stopCamera} className="p-2 bg-white/10 rounded-full">
                    <X size={24} />
                </button>
            </div>

            <div className="flex-1 relative flex items-center justify-center overflow-hidden bg-slate-900">
                <video
                    ref={videoRef}
                    autoPlay
                    muted
                    playsInline
                    className="w-full h-full object-contain"
                />
                <div className="absolute inset-0 border-2 border-white/20 pointer-events-none flex items-center justify-center">
                    <div className="w-64 h-64 border border-dashed border-white/40 rounded-lg"></div>
                </div>
            </div>

            <div className="h-32 bg-black flex items-center justify-around px-8">
                <div className="w-12 h-12"></div> {/* Spacer */}
                <button 
                    onClick={capturePhoto}
                    className="w-20 h-20 rounded-full bg-white flex items-center justify-center active:scale-95 transition-transform border-4 border-slate-400"
                >
                    <div className="w-16 h-16 rounded-full border-2 border-black bg-white"></div>
                </button>
                <button 
                    onClick={() => {
                        stopCamera();
                        startCamera();
                    }}
                    className="p-3 bg-white/10 rounded-full text-white"
                    title="카메라 재시작"
                >
                    <RotateCcw size={24} />
                </button>
            </div>
        </div>
      )}

      <header className="border-b shadow-sm sticky top-0 z-20 bg-white border-gray-300">
        <div className="p-4 flex items-center justify-between border-b border-gray-200">
             <h1 className="text-lg md:text-xl font-extrabold tracking-tight text-gray-900 truncate">
                미세먼지 측정기 RAW DATA
            </h1>
        </div>

        <div className="grid grid-cols-4 bg-gray-100">
            {[1, 2, 3, 4].map(num => (
                <button
                    key={num}
                    onClick={() => setActiveSite(num)}
                    className={`py-3 text-sm font-bold border-b-2 transition-colors ${
                        activeSite === num 
                        ? 'bg-white text-blue-600 border-blue-600' 
                        : 'text-gray-500 border-transparent hover:bg-gray-200'
                    }`}
                >
                    SITE {num}
                </button>
            ))}
        </div>
      </header>

      <main className="flex-1 overflow-y-auto p-3 bg-gray-50">
        <div className="p-2 shadow-sm border mb-4 bg-white border-gray-200">
             <div className="mb-2 font-bold text-lg text-blue-700 flex justify-between items-center">
                <span>▶ SITE {activeSite} 입력 정보</span>
                {currentData.attachedImages.length > 0 && (
                  <span className="text-xs text-green-700 font-bold bg-green-100 px-2 py-1 rounded flex items-center gap-1">
                    <FileCheck size={12} /> {currentData.attachedImages.length}개 사진
                  </span>
                )}
             </div>

            <div className="border-2 border-gray-800 mb-4 bg-white">
                <div className="grid grid-cols-4">
                    <LabelCell>접수번호</LabelCell>
                    <div className="col-span-3 border border-gray-400 p-1 bg-yellow-50">
                        <input 
                            type="text" 
                            className="w-full h-full p-1 focus:outline-none focus:bg-white bg-transparent font-bold"
                            placeholder="접수번호 입력"
                            value={currentData.receptionNumber}
                            onChange={(e) => handleInputChange('receptionNumber', e.target.value)}
                        />
                    </div>
                </div>

                <div className="grid grid-cols-4">
                    <LabelCell>검사시작</LabelCell>
                    <InputCell 
                        type="date" 
                        value={currentData.inspectStartDate} 
                        onChange={(v) => handleInputChange('inspectStartDate', v)}
                        textSize="text-xs"
                    />
                    <LabelCell>검사종료</LabelCell>
                    <InputCell 
                        type="date" 
                        value={currentData.inspectEndDate} 
                        onChange={(v) => handleInputChange('inspectEndDate', v)} 
                        textSize="text-xs"
                    />

                    <LabelCell>모델</LabelCell>
                    <InputCell value={currentData.model} onChange={(v) => handleInputChange('model', v)} />
                    <LabelCell>제조번호</LabelCell>
                    <InputCell value={currentData.serialNumber} onChange={(v) => handleInputChange('serialNumber', v)} />

                    <LabelCell>스팬 필름</LabelCell>
                    <InputCell type="number" value={currentData.spanFilm} onChange={(v) => handleInputChange('spanFilm', v)} />
                    <LabelCell>중간 필름</LabelCell>
                    <InputCell type="number" value={currentData.midFilm} onChange={(v) => handleInputChange('midFilm', v)} />

                    <LabelCell>스팬 1</LabelCell>
                    <InputCell type="number" value={currentData.span1} onChange={(v) => handleInputChange('span1', v)} />
                    <LabelCell>유량</LabelCell>
                    <InputCell type="number" value={currentData.flowRate} onChange={(v) => handleInputChange('flowRate', v)} />

                    <LabelCell>반복성 1</LabelCell>
                    <InputCell type="number" value={currentData.repeat1} onChange={(v) => handleInputChange('repeat1', v)} />
                    <LabelCell>직선성</LabelCell>
                    <InputCell type="number" value={currentData.linearity} onChange={(v) => handleInputChange('linearity', v)} />

                    <LabelCell>반복성 2</LabelCell>
                    <InputCell type="number" value={currentData.repeat2} onChange={(v) => handleInputChange('repeat2', v)} />
                    <LabelCell>공시험 1</LabelCell>
                    <InputCell type="number" value={currentData.blank1} onChange={(v) => handleInputChange('blank1', v)} />

                    <LabelCell>반복성 3</LabelCell>
                    <InputCell type="number" value={currentData.repeat3} onChange={(v) => handleInputChange('repeat3', v)} />
                    <LabelCell>공시험 2</LabelCell>
                    <InputCell type="number" value={currentData.blank2} onChange={(v) => handleInputChange('blank2', v)} />

                    <LabelCell>스팬 2</LabelCell>
                    <InputCell type="number" value={currentData.span2} onChange={(v) => handleInputChange('span2', v)} />
                    <LabelCell>공시험 3</LabelCell>
                    <InputCell type="number" value={currentData.blank3} onChange={(v) => handleInputChange('blank3', v)} />
                </div>
            </div>

            <div className="space-y-3">
                <div className="grid grid-cols-2 gap-2">
                    <button 
                        onClick={startCamera}
                        className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 border-2 border-black shadow-sm flex flex-col items-center justify-center gap-1 active:scale-95 transition-all"
                    >
                        <Camera size={24} />
                        <span className="text-sm">사진 촬영</span>
                    </button>
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="bg-yellow-400 hover:bg-yellow-500 text-black font-bold py-4 border-2 border-black shadow-sm flex flex-col items-center justify-center gap-1 active:scale-95 transition-all"
                    >
                        <ImagePlus size={24} />
                        <span className="text-sm">갤러리 선택</span>
                    </button>
                </div>

                <input 
                    type="file" 
                    ref={fileInputRef}
                    accept="image/*"
                    multiple 
                    className="hidden" 
                    onChange={handleFileUpload}
                />

                {currentData.attachedImages.length > 0 && (
                    <div className="p-2 bg-slate-100 border border-slate-300 rounded flex items-center justify-between">
                        <span className="text-sm font-medium">{currentData.attachedImages.length}개의 사진이 첨부됨</span>
                        <button 
                            onClick={clearImages}
                            className="p-1 text-red-600 hover:bg-red-50 rounded"
                        >
                            <Trash2 size={20} />
                        </button>
                    </div>
                )}

                <button 
                    onClick={handleExportExcel}
                    className="w-full bg-orange-400 hover:bg-orange-500 text-black font-bold py-4 border-2 border-black shadow-sm flex items-center justify-center gap-2 active:scale-98 transition-all"
                >
                    <FileSpreadsheet size={24} />
                    <span>엑셀 파일 + 사진 출력</span>
                </button>
            </div>

        </div>
      </main>

      <footer className="p-3 space-y-2 border-t-2 border-gray-300 bg-gray-100">
        <button
            onClick={handleSave}
            className="w-full py-3 bg-green-200 text-green-900 border-2 border-black font-bold flex items-center justify-center gap-2 rounded shadow-sm hover:bg-green-300 active:scale-98 transition-all"
        >
            <Save size={20} />
            SITE {activeSite} 임시 저장
        </button>

        <div className="grid grid-cols-2 gap-2">
            <button 
                onClick={handleGlobalExport}
                className="w-full bg-gray-300 hover:bg-gray-400 text-black font-bold py-3 rounded border border-gray-400 flex items-center justify-center gap-2 text-sm"
            >
                <Download size={18} />
                전체 출력
            </button>
            <button className="w-full bg-gray-700 hover:bg-gray-800 text-white font-bold py-3 rounded border border-gray-800 flex items-center justify-center gap-2 text-sm">
                <Send size={18} />
                전체 전송
            </button>
        </div>
      </footer>
    </div>
  );
};

export default FormView;

import React, { useState, useRef, useEffect } from 'react';
import { Camera, FileSpreadsheet, Send, Save, Download, FileCheck, Trash2, X, Aperture, ImagePlus, RotateCcw, Maximize } from 'lucide-react';
import { RawDataForm, INITIAL_FORM_DATA, AttachedImage } from '../types';
import JSZip from 'jszip';

const LabelCell = ({ children }: { children?: React.ReactNode }) => (
  <div className="bg-gray-100 p-2 text-center text-sm font-bold border border-gray-400 flex items-center justify-center break-keep">
    {children}
  </div>
);

const InputCell = ({ 
  value, 
  onChange, 
  type = "text",
  placeholder = "",
  textSize = "text-sm"
}: { 
  value: string; 
  onChange: (val: string) => void;
  type?: string;
  placeholder?: string;
  textSize?: string;
}) => {
  const [inputType, setInputType] = useState(type === 'date' ? 'text' : type);

  return (
  <div className="border border-gray-400 p-1 bg-yellow-50">
    <input
      type={inputType}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      onFocus={(e) => {
        if (type === 'date') setInputType('date');
      }}
      onBlur={(e) => {
        if (type === 'date') setInputType('text');
      }}
      placeholder={placeholder}
      className={`w-full h-full px-1 py-1 text-center focus:outline-none focus:bg-white ${textSize} font-bold bg-transparent tracking-tighter`}
    />
  </div>
  );
};

const FormView: React.FC = () => {
  const [siteData, setSiteData] = useState<{ [key: number]: RawDataForm }>({
    1: { ...INITIAL_FORM_DATA },
    2: { ...INITIAL_FORM_DATA },
    3: { ...INITIAL_FORM_DATA },
    4: { ...INITIAL_FORM_DATA },
  });

  const [activeSite, setActiveSite] = useState<number>(1);
  const [showCamera, setShowCamera] = useState(false);
  const [isCameraLoading, setIsCameraLoading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    return () => {
        stopCamera();
    };
  }, []);

  const startCamera = async () => {
      setIsCameraLoading(true);
      try {
          const stream = await navigator.mediaDevices.getUserMedia({
              video: { 
                  facingMode: 'environment',
                  width: { ideal: 1920 },
                  height: { ideal: 1080 }
              }
          });
          if (videoRef.current) {
              videoRef.current.srcObject = stream;
          }
          setShowCamera(true);
      } catch (err) {
          console.error(err);
          alert("카메라를 시작할 수 없습니다. 권한 설정을 확인해주세요.");
      } finally {
          setIsCameraLoading(false);
      }
  };

  const stopCamera = () => {
      if (videoRef.current && videoRef.current.srcObject) {
          const stream = videoRef.current.srcObject as MediaStream;
          stream.getTracks().forEach(track => track.stop());
          videoRef.current.srcObject = null;
      }
      setShowCamera(false);
  };

  const capturePhoto = () => {
      if (videoRef.current && showCamera) {
          const video = videoRef.current;
          const canvas = document.createElement('canvas');
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
              const dataUrl = canvas.toDataURL('image/jpeg', 0.8);

              const timestamp = new Date().toLocaleTimeString('ko-KR', { hour12: false }).replace(/:/g, '');
              const newImage: AttachedImage = {
                  name: `SITE${activeSite}_${timestamp}.jpg`,
                  dataUrl: dataUrl
              };

              setSiteData(prev => ({
                  ...prev,
                  [activeSite]: {
                      ...prev[activeSite],
                      attachedImages: [...prev[activeSite].attachedImages, newImage]
                  }
              }));

              // 시각적 피드백을 위한 셔터 효과
              const flash = document.createElement('div');
              flash.className = 'fixed inset-0 bg-white z-[60] animate-out fade-out duration-300 pointer-events-none';
              document.body.appendChild(flash);
              setTimeout(() => flash.remove(), 300);
          }
      }
  };

  const currentData = siteData[activeSite];

  const handleInputChange = (key: keyof RawDataForm, value: string) => {
    setSiteData(prev => ({
      ...prev,
      [activeSite]: {
        ...prev[activeSite],
        [key]: value
      }
    }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const files = Array.from(e.target.files) as File[];
      const newImages: AttachedImage[] = [];
      let processedCount = 0;

      files.forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          newImages.push({
            name: file.name,
            dataUrl: reader.result as string
          });
          processedCount++;

          if (processedCount === files.length) {
             setSiteData(prev => ({
                ...prev,
                [activeSite]: {
                  ...prev[activeSite],
                  attachedImages: [...prev[activeSite].attachedImages, ...newImages] 
                }
             }));
          }
        };
        reader.readAsDataURL(file);
      });
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const clearImages = (e: React.MouseEvent) => {
      e.stopPropagation();
      if(window.confirm(`SITE ${activeSite}의 사진을 모두 삭제하시겠습니까?`)) {
          setSiteData(prev => ({
              ...prev,
              [activeSite]: {
                  ...prev[activeSite],
                  attachedImages: []
              }
          }));
      }
  };

  const downloadBlob = (blob: Blob, filename: string) => {
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const getSafeString = (str?: string) => str?.trim() || 'null';

  const getCsvFileName = (data: RawDataForm) => {
    return `${getSafeString(data.receptionNumber)}_${getSafeString(data.inspectEndDate)}_${getSafeString(data.model)}_${getSafeString(data.serialNumber)}.csv`;
  };

  const generateCsvContent = (data: RawDataForm) => {
    const { attachedImages, ...csvData } = data;
    const headers = Object.keys(csvData).join(',');
    const values = Object.values(csvData).map(v => typeof v === 'string' ? v.replace(/,/g, ' ') : v).join(',');
    return "\uFEFF" + headers + "\n" + values;
  };

  const dataURLtoBlob = (dataurl: string): Blob => {
      const arr = dataurl.split(',');
      const mimeMatch = arr[0].match(/:(.*?);/);
      const mime = mimeMatch ? mimeMatch[1] : 'image/png';
      const bstr = atob(arr[1]);
      let n = bstr.length;
      const u8arr = new Uint8Array(n);
      while(n--){
          u8arr[n] = bstr.charCodeAt(n);
      }
      return new Blob([u8arr], {type:mime});
  }

  const downloadImagesAsZip = async (data: RawDataForm) => {
     if (data.attachedImages.length === 0) return;
     const zip = new JSZip();
     data.attachedImages.forEach((img, idx) => {
         const blob = dataURLtoBlob(img.dataUrl);
         zip.file(`${idx+1}_${img.name}`, blob);
     });
     const content = await zip.generateAsync({ type: "blob" });
     downloadBlob(content, `SITE${activeSite}_Images.zip`);
  };

  const handleExportExcel = async () => {
    const csvContent = generateCsvContent(currentData);
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    downloadBlob(blob, getCsvFileName(currentData));

    if (currentData.attachedImages.length > 0) {
        await new Promise(resolve => setTimeout(resolve, 500)); 
        await downloadImagesAsZip(currentData);
    }
  };

  const handleGlobalExport = async () => {
    const csvZip = new JSZip();
    for (let i = 1; i <= 4; i++) {
      const data = siteData[i];
      csvZip.file(getCsvFileName(data), generateCsvContent(data));
      if (data.attachedImages.length > 0) {
          // 사이트별 사진도 개별 다운로드 실행
          await downloadImagesAsZip(data);
          await new Promise(r => setTimeout(r, 300));
      }
    }
    const content = await csvZip.generateAsync({ type: "blob" });
    downloadBlob(content, `전체_RAW_DATA.zip`);
  };

  return (
    <div className="flex flex-col h-full font-sans bg-white text-slate-900 relative">

